import React, { useState, useEffect } from 'react';
import Sidebar from '../components/Sidebar';
import Navbar from '../components/Navbar';

const MyBookings = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  // Mock booking data
  const mockBookings = [
    {
      id: 1,
      carName: 'Tesla Model S',
      carImage: 'https://via.placeholder.com/100x60?text=Tesla',
      startDate: '2024-01-15',
      endDate: '2024-01-20',
      pickupLocation: 'Downtown Office',
      status: 'active',
      totalPrice: 750,
      bookingDate: '2024-01-10'
    },
    {
      id: 2,
      carName: 'BMW X5',
      carImage: 'https://via.placeholder.com/100x60?text=BMW',
      startDate: '2024-01-01',
      endDate: '2024-01-05',
      pickupLocation: 'Airport Branch',
      status: 'completed',
      totalPrice: 600,
      bookingDate: '2023-12-28'
    },
    {
      id: 3,
      carName: 'Mercedes C-Class',
      carImage: 'https://via.placeholder.com/100x60?text=Mercedes',
      startDate: '2024-02-01',
      endDate: '2024-02-03',
      pickupLocation: 'Downtown Office',
      status: 'pending',
      totalPrice: 200,
      bookingDate: '2024-01-20'
    },
    {
      id: 4,
      carName: 'Audi A4',
      carImage: 'https://via.placeholder.com/100x60?text=Audi',
      startDate: '2023-12-10',
      endDate: '2023-12-15',
      pickupLocation: 'Airport Branch',
      status: 'cancelled',
      totalPrice: 400,
      bookingDate: '2023-12-05'
    }
  ];

  useEffect(() => {
    // Simulate loading data
    setTimeout(() => {
      setBookings(mockBookings);
      setLoading(false);
    }, 500);
  }, []);

  const handleCancelBooking = (bookingId) => {
    if (window.confirm('Are you sure you want to cancel this booking?')) {
      setBookings(bookings.map(booking => 
        booking.id === bookingId 
          ? { ...booking, status: 'cancelled' } 
          : booking
      ));
    }
  };

  const filteredBookings = bookings.filter(booking => {
    if (filter === 'all') return true;
    return booking.status === filter;
  });

  const getStatusBadge = (status) => {
    const statusClasses = {
      active: { background: '#10b981', color: 'white' },
      pending: { background: '#f59e0b', color: 'white' },
      completed: { background: '#3b82f6', color: 'white' },
      cancelled: { background: '#ef4444', color: 'white' }
    };
    const style = statusClasses[status] || statusClasses.active;
    return (
      <span style={{...styles.statusBadge, ...style}}>
        {status.charAt(0).toUpperCase() + status.slice(1)}
      </span>
    );
  };

  return (
    <div style={styles.container}>
      <Navbar />
      <Sidebar />
      
      <div style={styles.dashboardContent}>
        <div style={styles.pageHeader}>
          <h1 style={styles.pageTitle}>My Bookings</h1>
          <p style={styles.pageSubtitle}>View and manage your car rentals</p>
        </div>

        {/* Filter Tabs */}
        <div style={styles.filterTabs}>
          {['all', 'active', 'pending', 'completed', 'cancelled'].map(f => (
            <button 
              key={f}
              style={{
                ...styles.filterTab,
                ...(filter === f ? styles.filterTabActive : {})
              }}
              onClick={() => setFilter(f)}
            >
              {f.charAt(0).toUpperCase() + f.slice(1)} ({bookings.filter(b => f === 'all' || b.status === f).length})
            </button>
          ))}
        </div>

        {/* Bookings List */}
        {loading ? (
          <div style={styles.loading}>Loading bookings...</div>
        ) : filteredBookings.length === 0 ? (
          <div style={styles.emptyState}>
            <p>No bookings found</p>
          </div>
        ) : (
          <div style={styles.bookingsList}>
            {filteredBookings.map(booking => (
              <div key={booking.id} style={styles.bookingCard}>
                <div style={styles.bookingCarImage}>
                  <img 
                    src={booking.carImage} 
                    alt={booking.carName}
                    onError={(e) => {
                      e.target.src = 'https://via.placeholder.com/100x60?text=Car';
                    }}
                    style={styles.carImg}
                  />
                </div>
                
                <div style={styles.bookingDetails}>
                  <h3 style={styles.carName}>{booking.carName}</h3>
                  <div style={styles.bookingInfo}>
                    <p><strong>Pickup:</strong> {booking.startDate}</p>
                    <p><strong>Return:</strong> {booking.endDate}</p>
                    <p><strong>Location:</strong> {booking.pickupLocation}</p>
                    <p><strong>Booked on:</strong> {booking.bookingDate}</p>
                  </div>
                </div>

                <div style={styles.bookingActions}>
                  <div style={styles.bookingPrice}>
                    <span style={styles.priceLabel}>Total</span>
                    <span style={styles.priceValue}>${booking.totalPrice}</span>
                  </div>
                  
                  {getStatusBadge(booking.status)}
                  
                  {booking.status === 'pending' && (
                    <button 
                      style={styles.btnDanger}
                      onClick={() => handleCancelBooking(booking.id)}
                    >
                      Cancel Booking
                    </button>
                  )}
                  
                  {booking.status === 'active' && (
                    <button style={styles.btnSecondary}>
                      Extend Rental
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #e9eefb, #f9fbfe)',
  },
  dashboardContent: {
    marginLeft: '250px',
    marginTop: '60px',
    padding: '30px',
    overflowY: 'auto',
  },
  pageHeader: {
    marginBottom: '20px',
  },
  pageTitle: {
    color: '#121253',
    fontSize: '28px',
    fontWeight: '700',
    margin: '0 0 5px 0',
  },
  pageSubtitle: {
    color: '#555',
    fontSize: '14px',
    margin: 0,
  },
  filterTabs: {
    display: 'flex',
    gap: '10px',
    marginBottom: '20px',
    flexWrap: 'wrap',
  },
  filterTab: {
    padding: '10px 20px',
    border: 'none',
    background: '#e9eefb',
    borderRadius: '6px',
    cursor: 'pointer',
    fontWeight: '500',
    color: '#555',
    transition: 'all 0.3s ease',
  },
  filterTabActive: {
    background: '#3f42c7',
    color: 'white',
  },
  loading: {
    textAlign: 'center',
    padding: '40px',
    color: '#555',
  },
  emptyState: {
    textAlign: 'center',
    padding: '40px',
    color: '#555',
    background: 'white',
    borderRadius: '8px',
  },
  bookingsList: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
  },
  bookingCard: {
    background: 'white',
    padding: '20px',
    borderRadius: '8px',
    boxShadow: '0 5px 15px rgb(56 56 92 / 0.1)',
    display: 'flex',
    gap: '20px',
    flexWrap: 'wrap',
    alignItems: 'center',
  },
  bookingCarImage: {
    flex: '0 0 100px',
  },
  carImg: {
    width: '100px',
    height: '60px',
    objectFit: 'cover',
    borderRadius: '6px',
  },
  bookingDetails: {
    flex: '1',
    minWidth: '200px',
  },
  carName: {
    color: '#121253',
    margin: '0 0 10px 0',
    fontSize: '18px',
  },
  bookingInfo: {
    fontSize: '14px',
    color: '#555',
  },
  bookingActions: {
    flex: '0 0 200px',
    display: 'flex',
    flexDirection: 'column',
    gap: '10px',
    alignItems: 'flex-start',
  },
  bookingPrice: {
    display: 'flex',
    flexDirection: 'column',
  },
  priceLabel: {
    fontSize: '12px',
    color: '#888',
  },
  priceValue: {
    fontSize: '20px',
    fontWeight: 'bold',
    color: '#121253',
  },
  statusBadge: {
    padding: '5px 12px',
    borderRadius: '20px',
    fontSize: '12px',
    fontWeight: '600',
  },
  btnSecondary: {
    background: '#6b7280',
    border: 'none',
    color: 'white',
    padding: '10px 20px',
    borderRadius: '6px',
    fontWeight: '600',
    cursor: 'pointer',
  },
  btnDanger: {
    background: '#ef4444',
    border: 'none',
    color: 'white',
    padding: '10px 20px',
    borderRadius: '6px',
    fontWeight: '600',
    cursor: 'pointer',
  },
};

export default MyBookings;
